import{_ as e,o as i,c as o,a2 as s}from"./chunks/framework.BKG_UbFK.js";const h=JSON.parse('{"title":"Publicação","description":"","frontmatter":{},"headers":[],"relativePath":"pt/guide/publishing.md","filePath":"pt/guide/publishing.md"}'),t={name:"pt/guide/publishing.md"};function n(l,a,c,d,r,p){return i(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="publicacao" tabindex="-1">Publicação <a class="header-anchor" href="#publicacao" aria-label="Permalink to &quot;Publicação&quot;">​</a></h1><p>O Clearance publica três tipos de recursos via tags <code>vendor:publish</code>: configuração, migrações, e traduções. A configuração e as migrações são geridas automaticamente pelo instalador (ver <a href="/clearance-docs/pt/guide/installation.html">Instalação</a>); esta página cobre a publicação manual destes, e a publicação de traduções.</p><h2 id="configuracao" tabindex="-1">Configuração <a class="header-anchor" href="#configuracao" aria-label="Permalink to &quot;Configuração&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Publica <code>config/clearance.php</code> na sua aplicação. Ver a <a href="/clearance-docs/pt/guide/configuration.html">referência de configuração</a> para todas as chaves, o seu padrão, e a sua finalidade.</p><h2 id="traducoes" tabindex="-1">Traduções <a class="header-anchor" href="#traducoes" aria-label="Permalink to &quot;Traduções&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>Isto copia os 9 idiomas incluídos (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) para <code>lang/vendor/clearance/{locale}/ui.php</code> na sua aplicação. Para adicionar um novo idioma ou substituir strings num já existente, adicione um diretório de idioma ali, usando <code>en/ui.php</code> como referência canónica de chaves. Todos os idiomas expõem um conjunto de chaves idêntico, verificado por um teste dedicado a cada alteração.</p><h2 id="substituir-o-layout-do-painel" tabindex="-1">Substituir o layout do painel <a class="header-anchor" href="#substituir-o-layout-do-painel" aria-label="Permalink to &quot;Substituir o layout do painel&quot;">​</a></h2><p>A chave de configuração <code>layout</code> controla o layout Blade usado pelos componentes de página completa:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>Deixe-a como <code>null</code> para usar o layout Livewire padrão da sua aplicação, ou defina-a para uma view de layout específica para renderizar o painel dentro de uma estrutura personalizada.</p><h2 id="migracoes" tabindex="-1">Migrações <a class="header-anchor" href="#migracoes" aria-label="Permalink to &quot;Migrações&quot;">​</a></h2><p>As migrações do Clearance são publicadas e executadas automaticamente por <code>php artisan clearance:install</code> - o instalador também publica e executa primeiro as migrações do Spatie se a tabela <code>roles</code> ainda não existir. Ver <a href="/clearance-docs/pt/guide/installation.html">Instalação</a> para o fluxo completo passo a passo, e o <a href="/clearance-docs/pt/guide/installation.html#executar-o-instalador">aviso de perigo</a> sobre nunca executar um <code>migrate</code> simples numa instalação nova.</p><h2 id="relacionado" tabindex="-1">Relacionado <a class="header-anchor" href="#relacionado" aria-label="Permalink to &quot;Relacionado&quot;">​</a></h2><ul><li><a href="/clearance-docs/pt/guide/configuration.html">Referência de configuração</a> - todas as chaves de configuração</li><li><a href="/clearance-docs/pt/guide/installation.html">Instalação</a> - o fluxo completo do instalador</li><li><a href="/clearance-docs/pt/guide/migration.html">Migração</a> - <code>clearance:backfill</code> para instalações Spatie existentes</li></ul>`,16)])])}const g=e(t,[["render",n]]);export{h as __pageData,g as default};
